// Normaliza e valida os dados recebidos do formulário
const body = $input.first().json;

const nome = (body.nome || '').trim();
const whatsapp = (body.whatsapp || '').replace(/\D/g, ''); // remove não-dígitos
const area = (body.area || 'Outro').trim();
const mensagem = (body.mensagem || '').trim();

if (!nome || !whatsapp) {
  throw new Error('Nome e WhatsApp são obrigatórios');
}

// Formata número para Evolution API: 55 + DDD + número
const whatsappFormatado = whatsapp.startsWith('55') ? whatsapp : `55${whatsapp}`;

return [{
  json: { nome, whatsapp, whatsappFormatado, area, mensagem }
}];
